/* Root Variables */
:root {
  --bg-light: #f5f3f0;
  --bg-dark: #111111;
  --text-on-light: #1a1a1a;
  --text-on-dark: #f0ede8;
  --accent: #0066cc;
  --font-display: 'Sohne', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --font-body: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html, body {
  width: 100%;
  height: 100%;
  overflow-x: hidden;
}

body {
  background: var(--bg-light);
  color: var(--text-on-light);
  font-family: var(--font-body);
  font-size: 16px;
  line-height: 1.6;
}

/* Loader */
#loader {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: var(--bg-light);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 9999;
  pointer-events: all;
}

.loader-content {
  text-align: center;
}

.loader-brand {
  font-family: var(--font-display);
  font-size: 3rem;
  font-weight: 600;
  margin-bottom: 2rem;
  color: var(--text-on-light);
}

.loader-bar {
  width: 200px;
  height: 3px;
  background: #e0e0e0;
  border-radius: 2px;
  overflow: hidden;
  margin-bottom: 1rem;
}

.loader-progress {
  height: 100%;
  background: var(--accent);
  width: 0%;
  transition: width 0.1s ease;
}

.loader-percent {
  font-size: 0.875rem;
  color: #666;
}

#loader.hidden {
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.6s ease;
}

/* Header */
.site-header {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  padding: 1.5rem 2rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
  z-index: 100;
  background: transparent;
  transition: background 0.3s ease;
}

.site-header.scrolled {
  background: rgba(255, 255, 255, 0.95);
  backdrop-filter: blur(10px);
}

.nav-logo {
  font-family: var(--font-display);
  font-size: 1.5rem;
  font-weight: 600;
}

.nav-links {
  display: flex;
  list-style: none;
  gap: 2rem;
}

.nav-links a {
  color: var(--text-on-light);
  text-decoration: none;
  font-size: 0.95rem;
  transition: color 0.3s ease;
}

.nav-links a:hover {
  color: var(--accent);
}

/* Hero Section */
.hero-standalone {
  position: relative;
  height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--bg-dark);
  color: var(--text-on-dark);
  text-align: center;
  padding: 2rem;
}

.hero-content {
  max-width: 800px;
}

.section-label {
  display: inline-block;
  font-size: 0.875rem;
  text-transform: uppercase;
  letter-spacing: 1px;
  opacity: 0.7;
  margin-bottom: 1rem;
}

.hero-heading {
  font-family: var(--font-display);
  font-size: 12rem;
  font-weight: 700;
  line-height: 1;
  margin-bottom: 1rem;
  letter-spacing: -2px;
}

.hero-heading span {
  display: block;
}

.hero-tagline {
  font-size: 1.5rem;
  opacity: 0.8;
  margin-bottom: 3rem;
  font-weight: 300;
}

.scroll-indicator {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.5rem;
  margin-top: 3rem;
  opacity: 0.6;
  animation: bounce 2s infinite;
}

.arrow {
  font-size: 1.5rem;
}

@keyframes bounce {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(10px); }
}

/* Canvas */
.canvas-wrap {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100vh;
  z-index: 1;
  pointer-events: none;
  clip-path: circle(0% at 50% 50%);
}

canvas {
  display: block;
  width: 100%;
  height: 100%;
}

/* Dark Overlay */
#dark-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: var(--bg-dark);
  opacity: 0;
  pointer-events: none;
  z-index: 10;
}

/* Marquee */
.marquee-wrap {
  position: fixed;
  bottom: 5%;
  left: 0;
  right: 0;
  white-space: nowrap;
  overflow: hidden;
  opacity: 0;
  z-index: 50;
}

.marquee-text {
  display: inline-block;
  font-family: var(--font-display);
  font-size: 10vw;
  font-weight: 700;
  letter-spacing: -2px;
  white-space: nowrap;
  will-change: transform;
}

/* Scroll Container */
#scroll-container {
  position: relative;
  height: 800vh;
}

/* Scroll Sections */
.scroll-section {
  position: absolute;
  left: 0;
  right: 0;
  height: auto;
  transform: translateY(-50%);
  z-index: 20;
  pointer-events: auto;
}

.section-content {
  padding: 4rem 0;
}

.section-inner {
  max-width: 40vw;
}

.align-left .section-inner {
  margin-left: 5vw;
}

.align-right .section-inner {
  margin-left: calc(55vw + 5vw);
}

.section-heading {
  font-family: var(--font-display);
  font-size: 4rem;
  font-weight: 700;
  line-height: 1.1;
  margin: 1rem 0 1.5rem 0;
  letter-spacing: -1px;
}

.section-body {
  font-size: 1.1rem;
  line-height: 1.8;
  opacity: 0.8;
  margin-bottom: 1.5rem;
}

.section-link {
  display: inline-block;
  color: var(--accent);
  text-decoration: none;
  font-size: 0.95rem;
  transition: opacity 0.3s ease;
}

.section-link:hover {
  opacity: 0.7;
}

/* Stats Section */
.section-stats {
  width: 100%;
  padding: 4rem 0;
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 2rem;
  max-width: 1000px;
  margin: 0 auto;
}

.stat {
  text-align: center;
}

.stat-number {
  display: block;
  font-family: var(--font-display);
  font-size: 3.5rem;
  font-weight: 700;
  margin-bottom: 0.5rem;
}

.stat-suffix {
  display: inline-block;
  font-size: 1.5rem;
  opacity: 0.7;
}

.stat-label {
  display: block;
  font-size: 0.95rem;
  opacity: 0.6;
  margin-top: 0.5rem;
}

/* CTA Section */
.section-cta {
  width: 100%;
  padding: 4rem 0;
  text-align: center;
}

.cta-button {
  display: inline-block;
  padding: 1rem 2.5rem;
  font-family: var(--font-body);
  font-size: 1rem;
  font-weight: 600;
  background: var(--accent);
  color: white;
  border: none;
  border-radius: 4px;
  cursor: pointer;
  transition: all 0.3s ease;
  margin-top: 1rem;
}

.cta-button:hover {
  opacity: 0.9;
  transform: translateY(-2px);
}

/* Mobile Responsive */
@media (max-width: 768px) {
  #scroll-container {
    height: 550vh;
  }

  .hero-heading {
    font-size: 3rem;
  }

  .section-heading {
    font-size: 2rem;
  }

  .align-left .section-inner,
  .align-right .section-inner {
    max-width: 100%;
    margin-left: 1rem;
    margin-right: 1rem;
  }

  .stats-grid {
    grid-template-columns: 1fr;
    gap: 2rem;
  }

  .marquee-text {
    font-size: 5vw;
  }

  .nav-links {
    gap: 1rem;
    font-size: 0.85rem;
  }
}

